vec3 mus = .02 / (length(uv1+.45+dz*16));
float mus2 = clamp01(.01*abs(uv3.x-.5)/abs(uv3.y-.55)-dz*4);


float stars = clamp01(1/((vUv.x*3234224*vUv.y)%22345));

ret1 = GetPixel(fract(uv3));
ret1 *= 1.4-mask/2;;  // orig: 1-mask/2

float fmask = clamp01(1-lum(ret1*4));
ret2 = ret1  + mus * (1-mask) * 1.4 ;  // orig: * 2
ret = max(ret2, stars*(1-mask)*fmask) ;
ret += clamp01(q22*mus2*fmask);


